import type React from 'react';

import { Slot } from '@radix-ui/react-slot';

import { cn } from '../utils/cn';

export type BoxProps = React.ComponentProps<'div'> & { asChild?: boolean };

/**
 * An extremely thin abstraction around a div. This marks the div as a layout
 * and presentational component.
 */
function Box({ asChild, className, ...props }: BoxProps) {
  const Comp = asChild ? Slot : 'div';
  return <Comp className={cn(className)} {...props} />;
}

export { Box };
